/*
 *  PicoSoC - A simple example SoC using PicoRV32
 *
 *  Copyright (C) 2017  Clifford Wolf <clifford@clifford.at>
 *
 *  Permission to use, copy, modify, and/or distribute this software for any
 *  purpose with or without fee is hereby granted, provided that the above
 *  copyright notice and this permission notice appear in all copies.
 *
 *  THE SOFTWARE IS PROVIDED "AS IS" AND THE AUTHOR DISCLAIMS ALL WARRANTIES
 *  WITH REGARD TO THIS SOFTWARE INCLUDING ALL IMPLIED WARRANTIES OF
 *  MERCHANTABILITY AND FITNESS. IN NO EVENT SHALL THE AUTHOR BE LIABLE FOR
 *  ANY SPECIAL, DIRECT, INDIRECT, OR CONSEQUENTIAL DAMAGES OR ANY DAMAGES
 *  WHATSOEVER RESULTING FROM LOSS OF USE, DATA OR PROFITS, WHETHER IN AN
 *  ACTION OF CONTRACT, NEGLIGENCE OR OTHER TORTIOUS ACTION, ARISING OUT OF
 *  OR IN CONNECTION WITH THE USE OR PERFORMANCE OF THIS SOFTWARE.
 *
 */
/*
 *  simpleuart lightly modified by L. Doolittle from C. Wolf's original:
 *    cfg_divider is a direct input, rather than attaching to a host bus
 *    send_divcnt and recv_divcnt are now only 20 bits wide
 *    reg_dat_ names are shortened to b_
 *    actual data ports are now only 8 bits wide (not padded to 32)
 *    b_busy and b_dv are new outputs
 *    send_divcnt is now a down-counter with pipelined terminal count detect
 *
 *  Baud rate computation:
 *    One bit time is clk period * cfg_divider
 *    e.g., use cfg_divider = 13021 for 9600 baud with 125 MHz clk
 *    minimum valid value of cfg_divider is 2.
 */

// Should the 20-bit divider width be parameterized?
module simpleuart (
	input clk,
	input resetn,

	output ser_tx,
	input  ser_rx,

	input  [19:0] cfg_divider,

	input        b_we,
	input        b_re,
	input  [7:0] b_di,
	output [7:0] b_do,
	output       b_dv,
	output       b_busy
);

	reg [3:0] recv_state;
	reg [19:0] recv_divcnt;
	reg [7:0] recv_pattern;
	reg [7:0] recv_buf_data;
	reg recv_buf_valid;

	reg [9:0] send_pattern;
	reg [3:0] send_bitcnt;
	reg [19:0] send_divcnt;
	reg send_divcnt_done;
	reg send_dummy;


	assign b_busy = b_we && (send_bitcnt || send_dummy);
	assign b_do = recv_buf_valid ? recv_buf_data : ~0;
	assign b_dv = recv_buf_valid;

	always @(posedge clk) begin
		if (!resetn) begin
			recv_state <= 0;
			recv_divcnt <= 0;
			recv_pattern <= 0;
			recv_buf_data <= 0;
			recv_buf_valid <= 0;
		end else begin
			recv_divcnt <= recv_divcnt + 1;
			if (b_re)
				recv_buf_valid <= 0;
			case (recv_state)
				0: begin
					if (!ser_rx)
						recv_state <= 1;
					recv_divcnt <= 0;
				end
				1: begin
					if (2*recv_divcnt > cfg_divider) begin
						recv_state <= 2;
						recv_divcnt <= 0;
					end
				end
				10: begin
					if (recv_divcnt > cfg_divider) begin
						recv_buf_data <= recv_pattern;
						recv_buf_valid <= 1;
						recv_state <= 0;
					end
				end
				default: begin
					if (recv_divcnt > cfg_divider) begin
						recv_pattern <= {ser_rx, recv_pattern[7:1]};
						recv_state <= recv_state + 1;
						recv_divcnt <= 0;
					end
				end
			endcase
		end
	end

	assign ser_tx = send_pattern[0];

	always @(posedge clk) begin
		send_divcnt <= send_divcnt - 1;
		send_divcnt_done <= send_divcnt==2;
		if (!resetn) begin
			send_pattern <= ~0;
			send_bitcnt <= 0;
			send_divcnt <= cfg_divider;
			send_dummy <= 1;
		end else begin
			if (send_dummy && !send_bitcnt) begin
				send_pattern <= ~0;
				send_bitcnt <= 15;
				send_divcnt <= cfg_divider;
				send_dummy <= 0;
			end else
			if (b_we && !send_bitcnt) begin
				send_pattern <= {1'b1, b_di, 1'b0};
				send_bitcnt <= 10;
				send_divcnt <= cfg_divider;
			end else
			if (send_divcnt_done && send_bitcnt) begin
				send_pattern <= {1'b1, send_pattern[9:1]};
				send_bitcnt <= send_bitcnt - 1;
				send_divcnt <= cfg_divider;
			end
		end
	end
endmodule

`timescale 1ns / 1ns

module gmii_to_rgmii #(
   parameter in_phase_tx_clk=0,
   parameter idelay_value=0,
   parameter use_idelay=0
) (

    // RGMII physical interface with PHY
    output [3:0] rgmii_txd, // to PHY
    output rgmii_tx_ctl,    // to PHY
    output rgmii_tx_clk,    // to PHY
    input [3:0] rgmii_rxd,  // from PHY
    input rgmii_rx_ctl,     // from PHY
    input rgmii_rx_clk,     // from PHY

    // GMII internal interface with MAC
    input gmii_tx_clk,      // from MAC
    input gmii_tx_clk90,    // from MAC
    input [7:0] gmii_txd,   // from MAC
    input gmii_tx_en,       // from MAC
    input gmii_tx_er,       // from MAC
    output [7:0] gmii_rxd,  // to MAC
    output gmii_rx_clk,     // to MAC
    output gmii_rx_dv,      // to MAC
    output gmii_rx_er,      // to MAC

    // IDELAYE2 control, matches lvds_iophy
    input            clk_div,
    input            idelay_ce,
    input [4:0]      idelay_value_in,
    output [4:0]     idelay_value_out_ctl,
    output [4:0]     idelay_value_out_data
);

// RGMII
wire [3:0] rgmii_txd_obuf;
wire [3:0] rgmii_rxd_ibuf;
wire rgmii_tx_ctl_buf;
wire rgmii_tx_clk_buf;
wire rgmii_rx_ctl_ibuf;
wire rgmii_rx_clk_buf;

OBUF rgmii_tx_ctl_obuf_i (
    .I(rgmii_tx_ctl_buf),
    .O(rgmii_tx_ctl)
);

OBUF rgmii_tx_clk_obuf_i (
    .I(rgmii_tx_clk_buf),
    .O(rgmii_tx_clk)
);

genvar ox;
generate for (ox=0; ox<4; ox=ox+1)
    begin: gen_rgmii_txd_obuf
        OBUF rgmii_txd_obuf_i (
            .I(rgmii_txd_obuf[ox]),
            .O(rgmii_txd[ox])
        );
    end
endgenerate

IBUF rgmii_rx_ctl_ibuf_i (
    .O(rgmii_rx_ctl_ibuf),
    .I(rgmii_rx_ctl)
);

IBUF rgmii_rx_clk_ibuf_i (
    .O(rgmii_rx_clk_buf),
    .I(rgmii_rx_clk)
);

genvar ix;
generate for (ix=0; ix<4; ix=ix+1)
    begin: gen_rgmii_rxd_ibuf
        IBUF rgmii_rxd_ibuf_i (
            .O(rgmii_rxd_ibuf[ix]),
            .I(rgmii_rxd[ix])
        );
    end
endgenerate

// Notes here refer to PG051, which is
//  Tri-Mode Ethernet MAC LogiCORE IP Product Guide (PG051)
// currently v9.0, May 17, 2023.  Of course my figure references
// are for a much older version, going back to at least 2018.
//
// RGMII Tx, Refer to PG051 Fig 3-66
// Refer to PG051 page 154 for reason of using ODDR & 90 phase clock.
// Other hardware (like Marvell 88E1512 in default mode)
// wants an in-phase clock.
wire rgmii_tx_clk_ = in_phase_tx_clk ? gmii_tx_clk : gmii_tx_clk90;
ODDR #(
    .DDR_CLK_EDGE  ("SAME_EDGE")
) rgmii_tx_clk_oddr (
    .Q(rgmii_tx_clk_buf),
    .C(rgmii_tx_clk_),
    .CE(1'b1),
    .D1(1'b1),
    .D2(1'b0),
    .R(1'b0),
    .S(1'b0)
);

// rgmii_tx_ctl
ODDR #(
    .DDR_CLK_EDGE("SAME_EDGE")
) rgmii_tx_ctl_oddr (
    .Q(rgmii_tx_ctl_buf),
    .C(gmii_tx_clk),
    .CE(1'b1),
    .D1(gmii_tx_en),
    .D2(gmii_tx_en ^ gmii_tx_er),
    .R(1'b0),
    //.R(tx_reset),
    .S(1'b0)
);

// rgmii_txd
wire [3:0] gmii_txd_rise = gmii_txd[3:0];
wire [3:0] gmii_txd_fall = gmii_txd[7:4];

genvar i;
generate for (i=0; i<4; i=i+1)
    begin: gen_rgmii_txd_oddr
        ODDR #(
            .DDR_CLK_EDGE("SAME_EDGE")
        ) rgmii_txd_oddr (
            .Q(rgmii_txd_obuf[i]),
            .C(gmii_tx_clk),
            .CE(1'b1),
            .D1(gmii_txd_rise[i]),
            .D2(gmii_txd_fall[i]),
            .R(1'b0),
            //.R(tx_reset),
            .S(1'b0)
        );
    end
endgenerate

// RGMII Rx, refer to PG051 Fig 3-67
// refer to PG051 page 155 for using BUFIO + BUFR + IODELAY
// rgmii_rx_clk
wire rgmii_rx_clk_bufio, rgmii_rx_clk_bufr;

BUFIO rgmii_rx_clk_bufio_i (
    .I(rgmii_rx_clk_buf),
    .O(rgmii_rx_clk_bufio)
);

BUFR rgmii_rx_clk_bufr_i (
    .I(rgmii_rx_clk_buf),
    .CE(1'b1),
    .CLR(1'b0),
    .O(rgmii_rx_clk_bufr)
);

assign gmii_rx_clk = rgmii_rx_clk_bufr;

// AC701 seems to not need RX delay.
// Note that this chunk of code delays rxd (and ctl) but not clk.
//
// I'm pretty sure that instantiating IDELAY doesn't really change the hardware;
// that block is always present in the data flow from the I/O pin, just set to
// a minimum delay configuration.
//
// Instantiating it does two things:  gives us access to the control pins,
// and the tools then force us to instantiate an IDELAYCTRL block somewhere
// to define calibration.
//
// Leaving it non-instantiated (parameter use_idelay=0) constructs the
// hdl as a bare wire, speeding and simplifying simulation, and avoiding
// the need to instantiate an IDELAYCTRL.
wire rgmii_rx_ctl_delay;
wire [3:0] rgmii_rxd_delay;
genvar j;
generate if (use_idelay) begin : with_idelay

wire [4:0] idelay_rx_ctl_value_out;
assign idelay_value_out_ctl = idelay_rx_ctl_value_out;
(* IODELAY_GROUP = "IODELAY_200" *)
IDELAYE2 #(
    .DELAY_SRC("IDATAIN"),
    .IDELAY_TYPE("VAR_LOAD"),
    .IDELAY_VALUE(idelay_value)
) rgmii_rx_ctl_delay_i (
    .IDATAIN(rgmii_rx_ctl_ibuf),
    .DATAOUT(rgmii_rx_ctl_delay),
    .DATAIN(1'b0),
    .C(clk_div),
    .CE(1'b0),
    .INC(1'b0),
    .CINVCTRL(1'b0),
    .CNTVALUEIN(idelay_value_in),
    .CNTVALUEOUT(idelay_rx_ctl_value_out),
    .LD(idelay_ce),
    .LDPIPEEN(1'b0),
    .REGRST(1'b0)
);

wire [4:0] idelay_rxd_value_out [0:3];  // [1:3] ignored
assign idelay_value_out_data = idelay_rxd_value_out[0];
for (j=0; j<4; j=j+1)
    begin: gen_gmii_rxd_delay
        (* IODELAY_GROUP = "IODELAY_200" *)
        IDELAYE2 #(
            .DELAY_SRC("IDATAIN"),
            .IDELAY_TYPE("VAR_LOAD"),
            .IDELAY_VALUE(idelay_value)
        ) delay_rgmii_rxd (
            .IDATAIN(rgmii_rxd_ibuf[j]),
            .DATAOUT(rgmii_rxd_delay[j]),
            .DATAIN(1'b0),
            .C(clk_div),
            .CE(1'b0),
            .INC(1'b0),
            .CINVCTRL(1'b0),
            .CNTVALUEIN(idelay_value_in),
            .CNTVALUEOUT(idelay_rxd_value_out[j]),
            .LD(idelay_ce),
            .LDPIPEEN(1'b0),
            .REGRST(1'b0)
        );
    end

end else begin : without_idelay
// pass-through
assign rgmii_rx_ctl_delay = rgmii_rx_ctl_ibuf;
assign rgmii_rxd_delay = rgmii_rxd_ibuf;
assign idelay_value_out_ctl = 0;
assign idelay_value_out_data = 0;
end endgenerate

// rgmii_rx_ctl
wire gmii_rx_dv_int;
wire rgmii_rx_ctl_int;

IDDR #(
    .DDR_CLK_EDGE("SAME_EDGE_PIPELINED")
) rgmii_rx_ctl_iddr (
    .Q1(gmii_rx_dv_int),
    .Q2(rgmii_rx_ctl_int),
    .C(rgmii_rx_clk_bufio),
    .CE(1'b1),
    .D(rgmii_rx_ctl_delay),
    .R(1'b0),
    .S(1'b0)
);

// Decode gmii_rx_er
assign gmii_rx_er = gmii_rx_dv_int ^ rgmii_rx_ctl_int;
assign gmii_rx_dv = gmii_rx_dv_int;

// rgmii_rxd

wire [3:0] gmii_rxd_rise, gmii_rxd_fall;
assign gmii_rxd = {gmii_rxd_fall, gmii_rxd_rise};

genvar k;
generate for (k=0; k<4; k=k+1)
    begin: gen_rgmii_rxd_iddr
        IDDR #(
            .DDR_CLK_EDGE("SAME_EDGE_PIPELINED")
        ) rgmii_rxd_iddr (
            .Q1(gmii_rxd_rise[k]),
            .Q2(gmii_rxd_fall[k]),
            .C(rgmii_rx_clk_bufio),
            .CE(1'b1),
            .D(rgmii_rxd_delay[k]),
            .R(1'b0),
            .S(1'b0)
        );
    end
endgenerate

endmodule

// Gives some simple cross-check of dec_8b10b against
// tables published in Wikipedia
//   https://en.wikipedia.org/wiki/8b10b
// and also gives a mechanism to convert 10b codes (supplied in a file)
// to human-readable form.
// XXX still kind of raw

module dec_8b10b_tb;

reg clk;
reg fail=0;
integer cc;
integer infile=0;
reg [255:0] init_file;
reg disp;
integer checked=0;
initial begin
	if ($test$plusargs("vcd")) begin
		$dumpfile("dec_8b10b.vcd");
		$dumpvars(5, dec_8b10b_tb);
	end
	if ($value$plusargs("init_file=%s", init_file)) begin
		infile = $fopen(init_file, "r");
	end
	if (!$value$plusargs("init_disp=%s", disp)) disp=0;
	for (cc=0; cc<200; cc=cc+1) begin
		clk=0; #4;
		clk=1; #4;
	end
	if (checked < 10) fail=1;
	if (fail) begin
		$display("FAIL");
		$stop(0);
	end else begin
		$display("PASS");
		$finish(0);
	end
end

integer rc, inp;
reg valid;
reg [9:0] i10;
always @(posedge clk) begin
	valid <= 0;
	if (infile) begin
		rc = $fscanf(infile, "%x\n", inp);
		if (rc==1) begin
			i10 <= inp;
			valid <= 1;
		end
	end
end

wire [5:0] abcdei = {i10[0], i10[1], i10[2], i10[3], i10[4], i10[5]};
wire [3:0] fghj   = {i10[6], i10[7], i10[8], i10[9]};

reg [4:0] edcba;
reg ki, vi;
always @(*) case (abcdei)
   6'b100111: begin edcba = 5'b00000; ki=0; vi=1; end
   6'b011000: begin edcba = 5'b00000; ki=0; vi=1; end
   6'b011101: begin edcba = 5'b00001; ki=0; vi=1; end
   6'b100010: begin edcba = 5'b00001; ki=0; vi=1; end
   6'b101101: begin edcba = 5'b00010; ki=0; vi=1; end
   6'b010010: begin edcba = 5'b00010; ki=0; vi=1; end
   6'b110001: begin edcba = 5'b00011; ki=0; vi=1; end
   6'b110101: begin edcba = 5'b00100; ki=0; vi=1; end
   6'b001010: begin edcba = 5'b00100; ki=0; vi=1; end
   6'b101001: begin edcba = 5'b00101; ki=0; vi=1; end
   6'b011001: begin edcba = 5'b00110; ki=0; vi=1; end
   6'b111000: begin edcba = 5'b00111; ki=0; vi=1; end
   6'b000111: begin edcba = 5'b00111; ki=0; vi=1; end
   6'b111001: begin edcba = 5'b01000; ki=0; vi=1; end
   6'b100101: begin edcba = 5'b01001; ki=0; vi=1; end
   6'b010101: begin edcba = 5'b01010; ki=0; vi=1; end
   6'b110100: begin edcba = 5'b01011; ki=0; vi=1; end
   6'b001101: begin edcba = 5'b01100; ki=0; vi=1; end
   6'b101100: begin edcba = 5'b01101; ki=0; vi=1; end
   6'b011100: begin edcba = 5'b01110; ki=0; vi=1; end
   6'b010111: begin edcba = 5'b01111; ki=0; vi=1; end
   6'b101000: begin edcba = 5'b01111; ki=0; vi=1; end
   6'b011011: begin edcba = 5'b10000; ki=0; vi=1; end
   6'b100100: begin edcba = 5'b10000; ki=0; vi=1; end
   6'b100011: begin edcba = 5'b10001; ki=0; vi=1; end
   6'b010011: begin edcba = 5'b10010; ki=0; vi=1; end
   6'b110010: begin edcba = 5'b10011; ki=0; vi=1; end
   6'b001011: begin edcba = 5'b10100; ki=0; vi=1; end
   6'b101010: begin edcba = 5'b10101; ki=0; vi=1; end
   6'b011010: begin edcba = 5'b10110; ki=0; vi=1; end
   6'b111010: begin edcba = 5'b10111; ki=0; vi=1; end
   6'b000101: begin edcba = 5'b10111; ki=0; vi=1; end
   6'b110011: begin edcba = 5'b11000; ki=0; vi=1; end
   6'b001100: begin edcba = 5'b11000; ki=0; vi=1; end
   6'b100110: begin edcba = 5'b11001; ki=0; vi=1; end
   6'b010110: begin edcba = 5'b11010; ki=0; vi=1; end
   6'b110110: begin edcba = 5'b11011; ki=0; vi=1; end
   6'b001001: begin edcba = 5'b11011; ki=0; vi=1; end
   6'b001110: begin edcba = 5'b11100; ki=0; vi=1; end
   6'b101110: begin edcba = 5'b11101; ki=0; vi=1; end
   6'b010001: begin edcba = 5'b11101; ki=0; vi=1; end
   6'b011110: begin edcba = 5'b11110; ki=0; vi=1; end
   6'b100001: begin edcba = 5'b11110; ki=0; vi=1; end
   6'b101011: begin edcba = 5'b11111; ki=0; vi=1; end
   6'b010100: begin edcba = 5'b11111; ki=0; vi=1; end
   6'b001111: begin edcba = 5'b11100; ki=1; vi=1; end
   6'b110000: begin edcba = 5'b11100; ki=1; vi=1; end
   default:   begin edcba = 5'bxxxxx; ki=0; vi=0; end
endcase

// Relatively brain-dead accounting for disparity flowing through
// the 5b/6b part of the decoder, to pass on to the 3b/4b part below.
reg [2:0] sum6;
reg disp6, disp6e;
always @(*) begin
	sum6 = abcdei[0] + abcdei[1] + abcdei[2] + abcdei[3] + abcdei[4] + abcdei[5];
	case (sum6)
		3'd2:    begin disp6=0;    disp6e=~disp; end
		3'd3:    begin disp6=disp; disp6e=0;     end // no change
		3'd4:    begin disp6=1;    disp6e=disp;  end
		default: begin disp6=disp; disp6e=1;     end // bad
	endcase
end

reg [2:0] hgf;
reg vj;
wire [5:0] KRDfghj = {ki, disp6, fghj};
always @(*) case (KRDfghj)
   6'b00_1011:  begin hgf = 3'b000; vj=1; end
   6'b01_0100:  begin hgf = 3'b000; vj=1; end
   6'b00_1001:  begin hgf = 3'b001; vj=1; end
   6'b01_1001:  begin hgf = 3'b001; vj=1; end
   6'b00_0101:  begin hgf = 3'b010; vj=1; end
   6'b01_0101:  begin hgf = 3'b010; vj=1; end
   6'b00_1100:  begin hgf = 3'b011; vj=1; end
   6'b01_0011:  begin hgf = 3'b011; vj=1; end
   6'b00_1101:  begin hgf = 3'b100; vj=1; end
   6'b01_0010:  begin hgf = 3'b100; vj=1; end
   6'b00_1010:  begin hgf = 3'b101; vj=1; end
   6'b01_1010:  begin hgf = 3'b101; vj=1; end
   6'b00_0110:  begin hgf = 3'b110; vj=1; end
   6'b01_0110:  begin hgf = 3'b110; vj=1; end
   6'b00_0111:  begin hgf = 3'b111; vj=1; end
   6'b01_1000:  begin hgf = 3'b111; vj=1; end
   6'b10_1011:  begin hgf = 3'b000; vj=1; end
   6'b11_0100:  begin hgf = 3'b000; vj=1; end
   6'b10_0110:  begin hgf = 3'b001; vj=1; end
   6'b11_1001:  begin hgf = 3'b001; vj=1; end
   6'b10_1010:  begin hgf = 3'b010; vj=1; end
   6'b11_0101:  begin hgf = 3'b010; vj=1; end
   6'b10_1100:  begin hgf = 3'b011; vj=1; end
   6'b11_0011:  begin hgf = 3'b011; vj=1; end
   6'b10_1101:  begin hgf = 3'b100; vj=1; end
   6'b11_0010:  begin hgf = 3'b100; vj=1; end
   6'b10_0101:  begin hgf = 3'b101; vj=1; end
   6'b11_1010:  begin hgf = 3'b101; vj=1; end
   6'b10_1001:  begin hgf = 3'b110; vj=1; end
   6'b11_0110:  begin hgf = 3'b110; vj=1; end
   6'b10_0111:  begin hgf = 3'b111; vj=1; end
   6'b11_1000:  begin hgf = 3'b111; vj=1; end
   default:     begin hgf = 3'bxxx; vj=0; end
endcase

reg [2:0] sum4;
reg disp4, disp4e;
always @(*) begin
	sum4 = fghj[0] + fghj[1] + fghj[2] + fghj[3];
	case (sum4)
		3'd1:    begin disp4=0;     disp4e=~disp6; end
		3'd2:    begin disp4=disp6; disp4e=0;      end
		3'd3:    begin disp4=1;     disp4e=disp6;  end
		default: begin disp4=disp6; disp4e=1;      end
	endcase
end

wire t_valid = vi & vj;
wire [8:0] o9 = {ki, hgf, edcba};

wire dispout;
wire [8:0] d9;
wire code_err, disp_err;
dec_8b10b dut(.datain(i10), .dispin(disp),
	.dataout(d9), .dispout(dispout),
	.code_err(code_err), .disp_err(disp_err));
always @(posedge clk) if (valid) disp <= dispout;

reg match;
always @(negedge clk) begin
	if (valid) begin
		match = o9 == d9;
		$display(" %3x   %b %b   %s.%d.%d  %x   %s.%d.%d  %x  %s",
		i10, abcdei, fghj,
		ki?"K":"D", edcba, hgf, o9,
		d9[8]?"K":"D", d9[4:0], d9[7:5], d9, match?".":"*");
		if (!match) fail=1;
		checked += 1;
	end
end

endmodule

