// TX state machine definitions
parameter [3:0]
  TX_COMMA = 0,
  TX_CR1 = 1,
  TX_CR2 = 2,
  TX_CR3 = 3,
  TX_CR4 = 4,
  TX_SPD = 5,
  TX_IDLE = 6,
  TX_DATA = 7,
  TX_EPD = 8,
  TX_EXTEND = 9;

initial begin
  tx_odata_reg=0;
  tx_is_k=0;
end

reg [3:0] tx_state=TX_COMMA;
reg tx_cr_alternate=0;
reg tx_odd_length=0;

// Two stages of passive data pipeline
reg [7:0] tx_data_p=0, tx_data_p2=0;
always @(posedge clk) tx_data_p <= tx_data_i;
always @(posedge clk) tx_data_p2 <= tx_data_p;
reg tx_enable_p=0;
always @(posedge clk) tx_enable_p <= tx_enable;

  always @(posedge clk) begin
    if((rst)) begin
      tx_state <= TX_COMMA;
      tx_odata_reg <= {8{1'b0}};
      tx_is_k <= 1'b 1;
      tx_cr_alternate <= 1'b 0;
      tx_odd_length <= 1'b 0;
    end
    else begin
      if((ep_tcr_en_pcs_i == 1'b 0)) begin
        tx_state <= TX_COMMA;
        tx_cr_alternate <= 1'b 0;
      end
      else begin
        case(tx_state)
        TX_COMMA : begin
          tx_is_k <= 1'b 1;
          tx_odata_reg <= c_k28_5;
          tx_state <= TX_IDLE;
        end
        TX_IDLE : begin
          // endpoint wants to send LCR register by pulsing tx_cr_send_i
          if((ep_lacr_tx_en_i == 1'b 1)) begin
            tx_state <= TX_CR1;
            tx_cr_alternate <= 1'b 0;
            // we've read something from the FIFO and it indicates a beginning of new frame
          end
          else if(tx_enable) begin
            tx_state <= TX_SPD;
          end
          else begin
            // continue sending idle sequences
            tx_state <= TX_COMMA;
          end
          tx_is_k <= 1'b 0;
          tx_odata_reg <= disparity_i ? c_d5_6 : c_d16_2;
        end
        TX_CR1 : begin
          tx_is_k <= 1'b 1;
          tx_odata_reg <= c_k28_5;
          tx_state <= TX_CR2;
        end
        TX_CR2 : begin
          tx_is_k <= 1'b 0;
          tx_odata_reg <= tx_cr_alternate ? c_d21_5 : c_d2_2;
          tx_cr_alternate <=  ~tx_cr_alternate;
          tx_state <= TX_CR3;
        end
        TX_CR3 : begin
          tx_odata_reg <= ep_lacr_tx_val_i[7:0]; // Little endian
          tx_state <= TX_CR4;
        end
        TX_CR4 : begin
          tx_odata_reg <= ep_lacr_tx_val_i[15:8];
          if((ep_lacr_tx_en_i == 1'b 1)) begin
            tx_state <= TX_CR1;
          end
          else begin
            tx_state <= TX_COMMA;
          end
        end
        TX_SPD : begin
          tx_is_k <= 1'b 1;
          tx_odata_reg <= c_k27_7;
          tx_odd_length <= 1'b 1;
          tx_state <= TX_DATA;
        end
        TX_DATA : begin
          tx_is_k <= 1'b 0;
          // send actual data
          tx_odata_reg <= tx_data_p2;
          // handle the end of frame both for even- and odd-length frames
          tx_odd_length <= ~tx_odd_length;
          if(~tx_enable_p) tx_state <= TX_EPD;
        end
        TX_EPD : begin
          tx_is_k <= 1'b 1;
          tx_odata_reg <= c_k29_7;
          tx_state <= TX_EXTEND;
        end
        TX_EXTEND : begin
          tx_odata_reg <= c_k23_7;
          if((tx_odd_length == 1'b 0)) begin
            tx_state <= TX_COMMA;
          end
          else begin
            tx_odd_length <= 1'b 0;
          end
        end
        default : begin

// Ethernet PCS autonegotiation
// https://www.iol.unh.edu/sites/default/files/knowledgebase/ge/Clause_37_Auto-Negotiation.pdf

// lacr == Link Autonegotiation Configuration Register
// module can clock over 180 MHz (need 125 MHz)
//
// Full-duplex only
// Next-page functionality not supported
// Pause frames not supported

module negotiate(
   input             rx_clk, // timespec 5.55 ns
   input             los,    // loss of signal
   // data received
   input [15:0]      lacr_in,
   input             lacr_in_stb,
   // data to be sent
   input             tx_clk,
   output reg [15:0] lacr_out,
   output reg        lacr_send,
   // mode control
   output reg        operate,
   output [8:0]      an_status
);
   // 10 ms link_timer = 10e6/8
   parameter TIMER_TICKS = 1250000;
   localparam TIMER_LOG2 = 21;

   // 16-bit Ethernet Configuration Register
   localparam NP_BITPOS   = 15,
              ACK_BITPOS  = 14,
              RF2_BITPOS  = 13,
              RF1_BITPOS  = 12,
              PS2_BITPOS  = 8,
              PS1_BITPOS  = 7,
              HD_BITPOS   = 6,
              FD_BITPOS   = 5,
              RSV1_HIGH   = 4,
              RSV1_LOW    = 0,
              RSV2_HIGH   = 11,
              RSV2_LOW    = 9;

   // Autonegotiation state machine
   localparam [2:0] AN_RESTART = 0,
                    AN_ABILITY = 1,
                    AN_ACK     = 2,
                    AN_IDLE    = 3,
                    AN_LINK_OK = 4,
                    AN_ABORT   = 5;

   reg [2:0] an_state = AN_RESTART, n_an_state = AN_RESTART;

   initial begin
     lacr_out=0;
     lacr_send=0;
     operate=0;
   end

   wire an_rst;
   // Detect physical link
